fun ExplorerScreen(viewModel: ConduitViewModel) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    var isSearching by remember { mutableStateOf(false) }
    var searchQuery by remember { mutableStateOf("") }

    var currentCategory by remember { mutableStateOf<String?>(null) }
    var categoryFiles by remember { mutableStateOf<List<FileItem>>(emptyList()) }
    var isScanning by remember { mutableStateOf(false) }

    val openCategory = { cat: String ->
        currentCategory = cat
        isScanning = true
        scope.launch(Dispatchers.IO) {
            val results = if (listOf("Images", "Videos", "Audio").contains(cat)) {
                FileScanner.getMediaFiles(context, cat)
            } else {
                // Use Python for Zips, Docs, etc.
                val python = com.chaquo.python.Python.getInstance()
                val executor = python.getModule("executor")
                val list = executor.callAttr("find_files_by_type", cat.lowercase()).asList()
                list.map { 
                    val p = it.toString()
                    FileItem(p.split("/").last(), p, Icons.Default.Description, Color(0xFFFFD740), p)
                }
            }
            withContext(Dispatchers.Main) {
                categoryFiles = results
                isScanning = false
            }
        }
    }

